mapper.update:
BEGIN
    EXECUTE IMMEDIATE '
        CREATE TABLE TEST_TASKLET (
            ID NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
            MESSAGE VARCHAR2(200),
            CREATED_AT TIMESTAMP DEFAULT SYSTIMESTAMP
        )';
EXCEPTION
    WHEN OTHERS THEN
        IF SQLCODE != -955 THEN
            RAISE;
        END IF;
END;
